ValidationRule.errorConditionFormula:
AND( $User.PS480FunctionValidationRulesActive__c =true,
OR( AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Draft", TEXT(InvoiceStatus__c) = "Sent" ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Approval", TEXT(InvoiceStatus__c) = "Sent" ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Ready", TEXT(InvoiceStatus__c) = "Draft", $User.IsFinanceManager__c = false
) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Ready", TEXT(InvoiceStatus__c) = "Approval", $User.IsFinanceManager__c = false ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Ready", TEXT(InvoiceStatus__c) = "Sent", $User.IsFinanceManager__c = false ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Sent", TEXT(InvoiceStatus__c) = "Draft" ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Sent", TEXT(InvoiceStatus__c) = "Approval" ) , AND( TEXT(PRIORVALUE(InvoiceStatus__c))="Sent", TEXT(InvoiceStatus__c) = "Ready", $User.IsFinanceManager__c = false
) ) )
